function initializeMockAttendanceHistory() {
    const existing = localStorage.getItem('lms-attendance-history');
    if (!existing || JSON.parse(existing).length < 5) {
        const mockHistory = [];
        const classes = ['m1', 'm2', 'm3'];
        const rooms = ['1', '2', '3'];

        const monthsData = [
            { name: 'มิ.ย.', year: 2569, days: [1, 2, 3, 4, 8, 9, 10, 11] },
            { name: 'พ.ค.', year: 2569, days: [12, 13, 14, 15, 19, 20, 21, 22] },
            { name: 'เม.ย.', year: 2569, days: [7, 8, 9, 10, 21, 22, 23, 24] },
            { name: 'มี.ค.', year: 2569, days: [3, 4, 5, 6, 10, 11, 12, 13] }
        ];

        monthsData.forEach(m => {
            m.days.forEach(d => {
                const dateStr = `${d} ${m.name} ${m.year}`;
                classes.forEach(cls => {
                    rooms.forEach(rm => {
                        const roster = studentRosters[cls]?.[rm] || studentRosters['m3']['1'];
                        const records = {};
                        let present = 0, late = 0, leave = 0, absent = 0;

                        roster.forEach((stu, idx) => {
                            let status = 'present';
                            const seed = (d + idx + parseInt(rm)) % 12;
                            if (seed === 0) {
                                status = 'absent';
                                absent++;
                            } else if (seed === 1) {
                                status = 'late';
                                late++;
                            } else if (seed === 2) {
                                status = 'leave';
                                leave++;
                            } else {
                                status = 'present';
                                present++;
                            }
                            records[stu.id] = status;
                        });

                        mockHistory.push({
                            date: dateStr,
                            class: cls,
                            room: rm,
                            total: roster.length,
                            present: present,
                            late: late,
                            leave: leave,
                            absent: absent,
                            rate: Math.round(((present + late + leave) / roster.length) * 100),
                            records: records
                        });
                    });
                });
            });
        });

        localStorage.setItem('lms-attendance-history', JSON.stringify(mockHistory));
    }
}

